targetScope = 'resourceGroup'

param oidcIssuerUrl string
param appWorkloadIdentityName string
param esoWorkloadIdentityName string

resource existingAppIdentity 'Microsoft.ManagedIdentity/userAssignedIdentities@2023-01-31' existing = {
  name: appWorkloadIdentityName
}

resource existingEsoIdentity 'Microsoft.ManagedIdentity/userAssignedIdentities@2023-01-31' existing = {
  name: esoWorkloadIdentityName
}

resource appFederatedCred 'Microsoft.ManagedIdentity/userAssignedIdentities/federatedIdentityCredentials@2023-01-31' = {
  parent: existingAppIdentity
  name: 'aks-craftedspecially-api'
  properties: {
    issuer: oidcIssuerUrl
    subject: 'system:serviceaccount:craftedspecially:craftedspecially-api'
    audiences: ['api://AzureADTokenExchange']
  }
}

resource esoFederatedCred 'Microsoft.ManagedIdentity/userAssignedIdentities/federatedIdentityCredentials@2023-01-31' = {
  parent: existingEsoIdentity
  name: 'aks-eso-controller'
  properties: {
    issuer: oidcIssuerUrl
    subject: 'system:serviceaccount:external-secrets:external-secrets'
    audiences: ['api://AzureADTokenExchange']
  }
}
---
targetScope = 'resourceGroup'

param location string
param projectName string

resource appWorkloadIdentity 'Microsoft.ManagedIdentity/userAssignedIdentities@2023-01-31' = {
  name: '${projectName}-api-identity'
  location: location
}

resource esoWorkloadIdentity 'Microsoft.ManagedIdentity/userAssignedIdentities@2023-01-31' = {
  name: '${projectName}-eso-identity'
  location: location
}

output appWorkloadIdentityClientId string = appWorkloadIdentity.properties.clientId
output appWorkloadIdentityPrincipalId string = appWorkloadIdentity.properties.principalId
output appWorkloadIdentityId string = appWorkloadIdentity.id
output appWorkloadIdentityName string = appWorkloadIdentity.name
output esoWorkloadIdentityClientId string = esoWorkloadIdentity.properties.clientId
output esoWorkloadIdentityPrincipalId string = esoWorkloadIdentity.properties.principalId
output esoWorkloadIdentityId string = esoWorkloadIdentity.id
output esoWorkloadIdentityName string = esoWorkloadIdentity.name
---
targetScope='subscription'

param projectLocation string = 'canadacentral'
param projectName string = 'CraftedSpecially'

// Creating resource group
resource rg 'Microsoft.Resources/resourceGroups@2021-01-01' = {
  name: projectName
  location: projectLocation
}

// Service group
resource root_service_group 'Microsoft.Management/serviceGroups@2024-02-01-preview' existing = {
  scope: tenant()
  name: 'health_model_test_tomb' // Root service group ID
}

resource service_group 'Microsoft.Management/serviceGroups@2024-02-01-preview' = {
  scope: tenant()
  kind: 'ServiceGroup'
  name: '${projectName}-servicegroup'
  properties: {
    displayName: '${projectName} Service Group'
    parent: {
      resourceId: root_service_group.id
    }
  }
}

module management_governance './modules/management_governance/management_governance.bicep' = {
  name: 'deployManagementGovernance'
  scope: rg
  params: {
    location: projectLocation
    projectName: projectName
  }
}

module application_infrastructure './modules/application_infrastructure/application_infrastructure.bicep' = {
  name: 'deployApplicationInfrastructure'
  scope: rg
  params: {
    location: projectLocation
    projectName: projectName
    appWorkloadIdentityPrincipalId: management_governance.outputs.appWorkloadIdentityPrincipalId
  }
}

module runtime_infrastructure './modules/runtime_infrastructure/runtime_infrastructure.bicep' = {
  name: 'deployRuntimeInfrastructure'
  scope: rg
  params: {
    projectLocation: projectLocation
    projectName: projectName
    containerRegistryName: management_governance.outputs.containerRegistryName
    serviceGroupName: service_group.name
  }
}

module federated_credentials './modules/management_governance/workload_identity/federated_credentials.bicep' = {
  name: 'deployFederatedCredentials'
  scope: rg
  params: {
    oidcIssuerUrl: runtime_infrastructure.outputs.oidcIssuerUrl
    appWorkloadIdentityName: management_governance.outputs.appWorkloadIdentityName
    esoWorkloadIdentityName: management_governance.outputs.esoWorkloadIdentityName
  }
}

